VALUES
  ('cpa-moex-00026', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依證券交易法之規定，下列何者不是上市公司得買回其股份之原因？', '["為維護公司信用及股東權益所必要而買回", "只要有股東要求公司買回時，無論其理由為何，公司即必須買回", "為轉讓股份予員工", "為配合可轉換公司債之發行，作為股權轉換之用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00027', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上櫃公司的董事長甲，為了實踐公開揭露原則，使得投資大眾能夠及時獲得有效且透明的公司 資料，特別要求公司會計部門主管乙，一定要遵守證券交易法之相關規定。下列敘述何者錯誤？', '["A公司應於每會計年度終了後三個月內，公告並申報經會計師查核簽證、董事會通過及監察人 承認之年度財務報告", "A公司應於每會計年度第一季、第二季及第三季終了後三十日內，公告並申報經會計師核閱及 提報董事會之財務報告", "A公司應於每月十日以前，公告並申報上月份營運情形", "若股東常會承認之年度財務報告與公告並向主管機關申報之年度財務報告不一致時，A公司應 於事實發生之日起二日內公告並向主管機關申報"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00028', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '在A公開發行公司服務之甲，於2020年10月至2022年1月間，連續利用業務上機會，以反覆 挪用方式連續侵占公司資金，雖有歸還一部分金額，實際侵占金額仍達新臺幣數百萬元之多。下 列敘述何者正確？', '["當甲具董事身分時，其侵占致公司遭受損害金額達新臺幣五百萬元以上，應依證券交易法第171 條處罰", "當甲具董事身分時，其侵占致公司遭受損害，不論金額高低，均應依證券交易法第171條處罰", "不論甲為公司董事或受僱人，其侵占致公司遭受損害金額達新臺幣五百萬元以上，均應依證券 交易法第171條處罰", "不論甲為公司董事或受僱人，其侵占致公司遭受損害，不論金額高低，均應依證券交易法第171 條處罰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00029', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲為股票上櫃之A股份有限公司（下稱A公司）之董事長，A公司於民國114年3月5日中午', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00030', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '時經董事會決議擬與 B 股份有限公司合併，甲於會議前 1 小時抵達會場閱讀會議資料，同日 下午1時A公司於公開資訊觀測站公告此合併消息，若甲下列何時點購買A公司股票構成內線', '["3月5日上午11時", "3月5日下午1時20分", "3月6日上午9時", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00031', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '商業會計法對於會計人員之規定，下列敘述何者錯誤？', '["股份有限公司之主辦會計人員之聘任，應由董事會以董事過半數之出席，及出席董事過半數之 同意", "有限公司之主辦會計人員之聘任，應有全體股東過半數之同意", "商業應設置會計人員", "公司任用會計師處理商業會計事務，應經監察人之同意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00032', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '商業會計法對於會計憑證之規定，下列敘述何者錯誤？', '["會計事項之發生，均應取得、給予或自行編製足以證明之會計憑證，違反者處罰對象包括商業 本身", "經濟部對於記帳憑證之名稱及格式有相關公告，但商業得依實際需要增訂", "對外憑證除應記載憑證名稱、日期、交易雙方名稱及地址或統一編號、交易內容及金額之外， 由開具人簽名或蓋章", "原始憑證因事實上限制無法取得，應根據事實或金額作成憑證，由商業負責人或其指定人員簽 名或蓋章，憑以記帳"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00033', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '採曆年制之商業，其決算最晚應於每年何時之前辦理完竣？', '["每年2月末日", "每年4月15日", "每年4月30日", "每年5月15日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00034', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'essay', '請依我國審計準則之相關規範，回答下列問題：
查核風險係指財務報表存有重大不實表達時，查核人員出具不適當
查核報告之風險，而查核風險受重大不實表達風險及偵查風險的影
響。重大不實表達風險與偵查風險之定義為何？（4 分）
查核人員為辨認可能產生重大不實表達風險之訴訟與索賠，應設計
並執行那些查核程序，請試列三項。（6 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00035', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'essay', '於 A公司 X4 年財務報表查核案件中，甲會計師事務所查核團隊有如
下查核結果：
㉑根據應收帳款函證抽樣結果，推估應收帳款帳載金額高估介於
200 萬元～500萬元之間。
㉒庫存現金經全部盤點後，發現比帳載額短少 300 萬元。
㉓ A 公司評估不動產、廠房及設備無減損跡象；查核團隊考量外部
來源資訊後，衡量未來現金流量估計，評估減損損失為 700萬元。
查核團隊依審計準則 320 號「查核規劃及執行重大性」決定之財務報
表整體重大性為3,500 萬元，特定交易類別、科目餘額或揭露事項之
重大性為900萬元～1,500萬元。
試作：
依審計準則 450 號「查核過程中所辨認不實表達之評估」規定，請
說明不實表達的類別有那幾類？並說明上述查核結果分別所屬
之類別。（9 分）
根據上述查核發現，彙總之不實表達金額為何？是否達到重大不實
表達程度？（6分）
管理階層拒絕更正查核團隊與其溝通之查核結果與調整建議，查核
人員如何因應？（5 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00036', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'essay', '會計師欲承接醫院急診部門有關成本效益認證之確信案件，其適用基
準可能包括提供服務之速度、服務之品質、值班期間照護之病患人數
及將服務成本與其他類似醫院比對之結果。請依確信準則 3000 號「非
屬歷史性財務資訊查核或核閱之確信案件」，回答下列問題：
會計師應從那些特性來評估上述基準具妥適性？（5分）
會計師選擇結合不同程序以取得合理確信，試舉出五種於規劃或執
行案件時可能採取之程序。（5 分）
當會計師查閱衛生福利部疾病管制署公布之相關文件，發現與標的
資訊間有重大不一致，試舉出三種可能採取之行動。（3 分）
若適用基準其中三項符合，另一項因些微差距而未符合，為取得合
理確信，會計師運用專業判斷，對該醫院之急診部門整體而言是否
符合成本效益可能作成何種結論？試論述之。（7分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00037', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列有關審計準則中對於可擴縮性之敘述，何者錯誤？', '["我國審計準則之基本準則適用所有企業之查核，無論其性質及情況複雜與否", "查核人員可使用自動化工具及技術執行風險評估程序", "在查核較不複雜受查者時，對於受查者之瞭解及相關事項無須全面書面化，為可擴縮性之 範例", "查核規模較小的企業，皆可適用審計準則中與可擴縮性有關之規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00038', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列有關品質管理準則2號「案件品質複核」之敘述，何者正確？', '["案件品質複核人員雖為案件服務團隊之成員，但對案件服務團隊所作之重大判斷及據此達 成之結論須執行客觀評估", "事務所應訂定政策或程序協助案件主辦會計師指派具備專業能力、適任能力之人員擔任案 件品質複核人員", "案件品質複核人員亦可為事務所外部之服務機構", "若案件品質複核人員對案件服務團隊所作之重大判斷是否適當存有未解決之疑慮時，案件 品質複核人員之主要責任係將此情形作成書面紀錄以釐清未來之責任歸屬"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00039', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關財務報導架構之說明，下列何者錯誤？', '["為符合廣大使用者對一般財務資訊需求所設計之財務報導架構為一般用途財務報導架構", "財團法人中華民國會計研究發展基金會發布之企業會計準則為一般用途財務報導架構", "一般用途財務報導架構通常為允當表達架構", "遵循架構係指財務報導架構，要求其遵循該架構規定，並明示或隱含管理階層可能需提供 超出架構所明訂之揭露"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00040', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關查核案件獨立性之敘述，下列何者正確？', '["查核案件小組成員家屬，係指其配偶（同居人）、子女及受扶養親屬", "受獨立性約束之重要查核會計師，除主辦會計師外，尚包含負責案件品質複核之人員", "若查核案件小組成員曾擔任受查核客戶之董監事，則可能因辯護緣故而影響其獨立性", "當查核案件小組成員收受受查核客戶董監事價值重大之禮物餽贈，則可能因自我利益緣故 而影響其獨立性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00041', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列有關會計師職業道德規範之敘述，何者正確？', '["會計師間不得相互介紹業務", "事務所中僅會計師必須遵循會計師職業道德規範", "會計師事務所設立分事務所，應由會計師親自主持", "會計師不得作任何宣傳或廣告"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00042', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關審計準則265號「內部控制缺失之溝通」之規定，下列敘述何者錯誤？', '["該準則所稱查核人員須與受查者溝通之內部控制缺失，僅限於就查核財務報表時所辨認之 內部控制缺失", "查核人員一定要以書面方式，與管理階層及治理單位溝通內部控制顯著缺失", "內部控制缺失是否顯著，取決於不實表達是否已實際發生及實際發生之潛在影響", "管理階層或治理單位如要求查核人員出具敘明其於查核過程中，未辨認出內部控制顯著缺 失之書面溝通，查核人員得出具該書面溝通"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00043', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '在規劃查核時，查核人員所考量之查核風險，下列敘述何者正確？', '["當財務報表存有重大不實表達時，查核人員無法適當修正其意見的風險", "受查者設置內部稽核人員，無法查出其帳戶餘額易遭受重大不實表達的風險", "與受查者的前任會計師聯繫，瞭解前任會計師未能辨認財務報表潛在重大之錯誤風險", "受查者設有內部控制制度，而仍無法偵出重大不實表達的風險"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00044', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '依據審計準則210號「查核案件條款之協議」，下列何項條款為必須記載於查核委任書或其他 適當形式之書面協議？', '["會計師賠償責任之限制", "酬金之確定金額及收款方式", "會計師查核財務報表之責任", "提供查核工作底稿予第三方之義務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00045', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關查核規劃作業之性質及範圍，下列何項非主要考量之因素？', '["查核團隊主要成員對受查者之查核經驗", "查核期間有關情況之改變", "查核公費的高低", "受查者之規模與複雜度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00046', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關財務報表之查核案件，下列程序之執行順序為何？①簽訂委任書  ②評估會計師職業道', '["向管理階層取得書面聲明", "瞭解受查者及其環境，以辨認並評估重大不 實表達風險  ⑤執行內部控制測試", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00047', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員於訂定整體查核策略時，下列何者通常非考量之事項？', '["與受查者溝通查核案件委任之內容", "辨認查核案件之特性以決定查核範圍", "依專業判斷考量重要因素，以指引查核團隊之查核方向", "確認執行查核案件所需資源之性質、時間及範圍"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00048', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '在查核案件中，下列何者是審計準則所稱查核團隊之成員？', '["執行查核案件之事務所聘僱之專家", "執行查核案件之查核人員外部專家", "案件品質複核人員", "主辦會計師決定在查核報告中提及之被提及查核人員"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00049', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關管理階層踰越控制之風險，下列何者錯誤？', '["管理階層踰越控制之風險存在所有受查者中", "無論所評估受查者管理當局踰越控制之風險高低，查核人員皆應測試會計分錄及編製財務 報表所做其他調整之適當性", "為評估管理階層踰越控制之風險，查核人員應評估受查客戶不尋常交易之動機及合理性", "評估管理階層踰越控制之風險，管理階層過去的誠信程度為主要考量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00050', 'cpa', 'cpa-moex-114-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '繼任會計師為對本期財務報表表示意見及查明本期財務報表所採用的會計政策是否與上期一 致，應蒐集足夠適切的證據，其蒐集方式不包括：', '["對重要之期初科目餘額與上期交易事項採行適當之查核程序", "向前任會計師查詢有關事項", "詢問管理階層的品德", "借閱前任會計師之工作底稿"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "3220df39efb4", "answer_pdf_sha1": "86d0642657d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
